use std::path::Path;
use std::time::{Duration, Instant};

struct FileWatcher {
    path: std::path::PathBuf,
}

impl FileWatcher {
    fn new(path: impl AsRef<Path>) -> Self {
        FileWatcher { path: path.as_ref().to_owned() }
    }

    fn watch(&self) -> Result<(), Box<dyn std::error::Error>> {
        let start = Instant::now();
        loop {
            std::thread::sleep(Duration::from_millis(500));
            match self.check_for_changes(start)? {
                true => println!("File change detected on: {}", self.path.display()),
                false => {},
            }
        }
    }

    fn check_for_changes(&self, start: Instant) -> Result<bool, std::io::Error> {
        let metadata = std::fs::metadata(&self.path)?;
        let _current_modified = metadata.modified()?;

        if start.elapsed() > Duration::from_secs(1) { 
            Ok(true)
        } else {
            Ok(false)
        }
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let path_to_watch = "./config.txt";
    if !Path::new(path_to_watch).exists() {
        std::fs::write(path_to_watch, "Initial content.")?;
    }

    let watcher = FileWatcher::new(path_to_watch);
    println!("Monitoring file changes for: {}", path_to_watch);
    match watcher.watch() {
        Ok(_) => Ok(()),
