        }
    }
}

use std::fs;
use std::path::Path;
use std::time::Duration;
use std::thread;
use std::io::{self, Write};

struct ConfigWatcher {
    path: String,
}

impl ConfigWatcher {
    fn new(path: &str) -> Self {
        ConfigWatcher {
            path: path.to_string(),
        }
    }

    fn watch(&self) -> io::Result<()> {
        let mut last_modified = fs::metadata(&self.path)?.modified()?;
        println!("Starting watch loop for file: {}", self.path);
        loop {
            thread::sleep(Duration::from_secs(2));
            match fs::metadata(&self.path) {
                Ok(metadata) => {
                    let current_modified = metadata.modified()?;
                    if current_modified > last_modified {
                        println!("n=========================================");
                        println!("File changed detected! Re-running logic...");
                        self.on_config_changed();
                        last_modified = current_modified;
                        println!("Logic update complete.n=========================================n");
                    }
                }
                Err(e) => {
                    eprintln!("Error reading metadata: {}", e);
                    return Err(e);
                }
            }
        }
    }

    fn on_config_changed(&self) {
        println!("Executing mod update routine based on new config state.");

        if let Ok(data) = fs::read_to_string(&self.path) {
            let line_count = data.lines().count();
            println!("Successfully read file content. Found {} lines to process.", line_count);
        } else {
            eprintln!("Could not read file for re-initialization check.");
        }
    }
}

use std::fs::File;
use std::io::{self, Read, Seek, SeekFrom};
use std::path::Path;

struct WALEngine {
    file_path: String,
    last_size: u64,
}

impl WALEngine {
    fn new(path: &str) -> io::Result<Self> {
        let path_ref = Path::new(path);
        let metadata = std::fs::metadata(path_ref)?;
        Ok(WALEngine {
            file_path: path.to_string(),
            last_size: metadata.len(),
        })
    }

    fn check_for_changes(&mut self) -> io::Result<u64> {
        let metadata = std::fs::metadata(Path::new(&self.file_path))?;
        let current_size = metadata.len();

        if current_size > self.last_size {
            println!("File grew. New data segment detected.");
            Ok(current_size)
        } else if current_size < self.last_size {
            println!("Warning: File shrunk unexpectedly. Resetting tracking.");
            self.last_size = current_size;
            Ok(current_size)
        } else {
            println!("No size change detected. Assuming stable state.");
            Ok(self.last_size)
        }
    }

    fn process_new_data(&mut self) -> io::Result<()> {
        let file = File::open(&self.file_path)?;
        let mut reader = io::BufReader::new(file);

        reader.seek(SeekFrom::Start(self.last_size))?;

        let mut buffer = Vec::new();
        reader.read_to_end(&mut buffer)?; 

        if !buffer.is_empty() {
            println!("Successfully read {} bytes of new transaction data.", buffer.len());
            let metadata = std::fs::metadata(Path::new(&self.file_path))?;
            self.last_size = metadata.len();
        }
        Ok(()) 
    }
}

fn main() -> io::Result<()> {
    let temp_path = "test_wal.log";
    std::fs::write(temp_path, "Initial transaction record.nData block 1.");

    let mut engine = WALEngine::new(temp_path)?;
    println!("--- Initial Check ---");
    let size = engine.check_for_changes()?;
    engine.process_new_data()?;

    std::fs::write(temp_path, "Initial transaction record.nData block 1.n--- New Write Transaction Data ---");

    println!("n--- Second Check After Write ---");
    let new_size = engine.check_for_changes()?;
    engine.process_new_data()?;

    std::thread::sleep(std::time::Duration::from_millis(10));
    println!("n--- Third Check (No Write) ---");
    let stable_size = engine.check_for_changes()?;
    engine.process_new_data()?;

    Ok(())
}

